"use client"

import type React from "react"

import { useState, useEffect } from "react"
import { createClient } from "@/lib/supabase/client"
import { Button } from "@/components/ui/button"
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Textarea } from "@/components/ui/textarea"
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"
import Link from "next/link"
import { useRouter } from "next/navigation"
import { ArrowLeft, Star, Check } from "lucide-react"
import type { Master } from "@/lib/types"

export default function NewReviewPage() {
  const router = useRouter()
  const supabase = createClient()

  const [masters, setMasters] = useState<Master[]>([])
  const [selectedMaster, setSelectedMaster] = useState<string>("")
  const [clientName, setClientName] = useState("")
  const [rating, setRating] = useState(0)
  const [comment, setComment] = useState("")
  const [isLoading, setIsLoading] = useState(false)
  const [success, setSuccess] = useState(false)

  useEffect(() => {
    loadMasters()
  }, [])

  const loadMasters = async () => {
    const { data } = await supabase.from("masters").select("*").eq("is_active", true).order("name")
    if (data) setMasters(data)
  }

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    if (!selectedMaster || rating === 0) {
      alert("Пожалуйста, выберите мастера и поставьте оценку")
      return
    }

    setIsLoading(true)

    try {
      const { error } = await supabase.from("reviews").insert({
        master_id: selectedMaster,
        client_name: clientName,
        rating,
        comment: comment || null,
        is_approved: false,
      })

      if (error) throw error

      setSuccess(true)
    } catch (error) {
      console.error("[v0] Review submission error:", error)
      alert("Произошла ошибка при отправке отзыва. Попробуйте снова.")
    } finally {
      setIsLoading(false)
    }
  }

  if (success) {
    return (
      <div className="min-h-screen bg-gradient-to-b from-rose-50 to-white flex items-center justify-center p-4">
        <Card className="max-w-md w-full">
          <CardContent className="pt-6 text-center">
            <div className="w-16 h-16 bg-green-100 rounded-full flex items-center justify-center mx-auto mb-4">
              <Check className="w-8 h-8 text-green-600" />
            </div>
            <h2 className="text-2xl font-bold mb-2">Спасибо за ваш отзыв!</h2>
            <p className="text-gray-600 mb-6">Ваш отзыв отправлен на модерацию и появится на сайте после проверки.</p>
            <Link href="/reviews">
              <Button className="w-full bg-rose-600 hover:bg-rose-700">К отзывам</Button>
            </Link>
          </CardContent>
        </Card>
      </div>
    )
  }

  return (
    <div className="min-h-screen bg-gradient-to-b from-rose-50 to-white">
      <div className="container mx-auto px-4 py-8">
        <div className="max-w-2xl mx-auto">
          <Link href="/reviews" className="inline-flex items-center gap-2 text-gray-600 hover:text-rose-600 mb-6">
            <ArrowLeft className="w-4 h-4" />
            Назад к отзывам
          </Link>

          <h1 className="text-4xl font-bold mb-8">Оставить отзыв</h1>

          <Card>
            <CardHeader>
              <CardTitle>Расскажите о вашем опыте</CardTitle>
            </CardHeader>
            <CardContent>
              <form onSubmit={handleSubmit} className="space-y-6">
                <div>
                  <Label htmlFor="name">Ваше имя *</Label>
                  <Input
                    id="name"
                    value={clientName}
                    onChange={(e) => setClientName(e.target.value)}
                    required
                    placeholder="Введите ваше имя"
                  />
                </div>

                <div>
                  <Label htmlFor="master">Мастер *</Label>
                  <Select value={selectedMaster} onValueChange={setSelectedMaster} required>
                    <SelectTrigger id="master">
                      <SelectValue placeholder="Выберите мастера" />
                    </SelectTrigger>
                    <SelectContent>
                      {masters.map((master) => (
                        <SelectItem key={master.id} value={master.id}>
                          {master.name} - {master.specialty}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>

                <div>
                  <Label>Оценка *</Label>
                  <div className="flex gap-2 mt-2">
                    {[1, 2, 3, 4, 5].map((star) => (
                      <button
                        key={star}
                        type="button"
                        onClick={() => setRating(star)}
                        className="transition-transform hover:scale-110"
                      >
                        <Star
                          className={`w-10 h-10 ${
                            star <= rating ? "fill-yellow-400 text-yellow-400" : "text-gray-300"
                          }`}
                        />
                      </button>
                    ))}
                  </div>
                  <p className="text-sm text-gray-600 mt-2">Выберите от 1 до 5 звезд</p>
                </div>

                <div>
                  <Label htmlFor="comment">Ваш отзыв *</Label>
                  <Textarea
                    id="comment"
                    value={comment}
                    onChange={(e) => setComment(e.target.value)}
                    required
                    placeholder="Расскажите о вашем опыте посещения салона..."
                    rows={6}
                  />
                </div>

                <Button type="submit" disabled={isLoading} className="w-full bg-rose-600 hover:bg-rose-700">
                  {isLoading ? "Отправка..." : "Отправить отзыв"}
                </Button>
              </form>
            </CardContent>
          </Card>
        </div>
      </div>
    </div>
  )
}
